using UnityEngine;

/// <summary>
/// Peso de jogo explícito de um objecto (Etapa 6.1 — caixas, pedras, etc),
/// usado por WeightPlate. Separado de Rigidbody2D.mass de propósito: a massa
/// do Unity afecta a física toda (knockback, colisões), enquanto este peso é
/// só "de jogo" (placas de peso, e futuros usos como empurrar/queda).
///
/// Prioridade na WeightPlate: ObjectWeight (se presente, vence sempre) >
/// player (peso da forma actual — AnimalFormData.weightMultiplier) > inimigo
/// (EnemyData.stats.weight) > Rigidbody2D.mass (fallback).
/// </summary>
[DisallowMultipleComponent]
public class ObjectWeight : MonoBehaviour
{
    [Tooltip("Peso de jogo deste objecto (1 = normal).")]
    [Min(0f)] public float weight = 1f;
}
